        Objects.requireNonNull(consumed, "consumed can't be null");
        internalStreamsBuilder.addGlobalStore(
            StoreBuilderWrapper.wrapStoreBuilder(storeBuilder),
            topic,
            new ConsumedInternal<>(consumed),
            stateUpdateSupplier,
            true
        );
        return this;
    }

